form:Form.form:Scripts:
		function ValidarDatos()
{               
      var blnDatosOK = false;

      blnDatosOK = EstaDisponible();

      if (blnDatosOK)
      {
				Ctrl("main").DoEvent("GUARDAR");
			}	 		
}     

	function EstaDisponible()
	{  
		//verifica si ya existe la variable en el Grupo o Subgrupos	
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var blnresult = true;

		var oi_grupo = Ctrl("PARENT").GetXValue();

		var c_grupo = GetValueFromQry(nSQL, "QRY_GRUPO", "<PARAMS oi_grupo=\"" + oi_grupo + "\"/>", "");        		

		//obtiene el grupo o la parte izquieda del punto (si contiene)
		var strpatron = (c_grupo.indexOf('.')>0?c_grupo.substring(0, c_grupo.indexOf('.')):c_grupo);		
		var lpatron = strpatron.length;

		var oi_variable = Ctrl("oi_variable").GetXValue();

		var strvariable = Ctrl("oi_variable").GetCValue();		

 	 	result = GetValuesFromQry(nSQL, "campo", "QRY_BUSCA_VAR", "<PARAMS patron=\""+ strpatron  + "\" lpatron=\""+ lpatron + "\" oi_variable=\"" + oi_variable + "\"/>","");		

		if (result != "")
		{
			alert("La variable (" + strvariable + ") ya se encuentra utilizada en los grupos (" + result + ")." );		
			blnresult = false;
		}

		return blnresult;
	}   

	function GetValueFromQry(pSQL, pQry, pFilters, vDefault)
	{ 
		//ejecuta el query recibido	con los filtros y retorna lo encontrado o el valor default

	  var valor;	
		var param = pSQL.GetOBJ(Ctrl("main").getResource(pQry), pFilters);	

		if (typeof (param.valor) != "undefined")
		{
			valor = param.valor;  //retorna el valor encontrado
		}
		else
		{
			valor = vDefault; //retorna el valor por default 
		} 

		return valor;
	}    

	function GetValuesFromQry(pSQL, pField, pQry, pFilters, vDefault)
	{ 
		//ejecuta el query recibido y retorna el valor del campo recibido separado por ,

		var xmlRESULT = pSQL.GetXML(Ctrl("main").getResource(pQry), pFilters);	
		var values = vDefault;

		//Recorre los registros hallados y concatena los oi_liquidacion
		var xmlItem, item=0;
		for (xmlItem = xmlRESULT.FirstChild(); xmlItem != null; xmlItem = xmlItem.Next()) 
		{	
			if (values != "") values += ","; 
			values += xmlItem.GetAttr(pField);			
		}

		return values;
	}
